def _backfill_tips(apps, schema_editor):
    """
    Convierte ventas legacy con `Sale.tip > 0` a filas de `SaleTip`.

    Reglas:
    - Si la venta tiene `tip_method` explícito → 1 SaleTip con esa propina y método.
    - Si `tip_method` está vacío → reparto proporcional según los SalePayments
      (la última fila absorbe el redondeo para que la suma cuadre exacto con
      `Sale.tip`). Si la venta no tiene payments, fallback a "cash".

    Idempotencia: sólo backfilea ventas que NO tengan filas SaleTip ya creadas.
    """
