    Sale = apps.get_model("sales", "Sale")
    SaleTip = apps.get_model("sales", "SaleTip")
    SalePayment = apps.get_model("sales", "SalePayment")

    sales_to_backfill = Sale.objects.filter(tip__gt=Decimal("0"))
    tips_to_create = []
